// Define the binary search tree class with insertion, deletion, and traversal functions
class BinarySearchTree {
    var root: Node?

    // Insert a new node with a given value
    func insert(value: Int) {
        let newNode = Node(value: value)
        if root == nil {
            root = newNode
        } else {
            insertNode(node: root, newNode: newNode)
        }
    }

    // Insert a new node recursively by traversing the tree
    func insertNode(node: Node?, newNode: Node) {
        if newNode.value < node!.value {
            if node!.leftChild == nil {
                node!.leftChild = newNode
            } else {
                insertNode(node: node!.leftChild, newNode: newNode)
            }
        } else if newNode.value > node!.value {
            if node!.rightChild == nil {
                node!.rightChild = newNode
            } else {
                insertNode(node: node!.rightChild, newNode: newNode)
            }
        }
    }

    // Delete a node with a given value
    func delete(value: Int) {
        root = deleteNode(node: root, value: value)
    }

    // Delete a node recursively by traversing the tree
    func deleteNode(node: Node?, value: Int) -> Node? {
        if node == nil {
            return node
        }

        if value < node!.value {
            node!.leftChild = deleteNode(node: node!.leftChild, value: value)
        } else if value > node!.value {
            node!.rightChild = deleteNode(node: node!.rightChild, value: value)
        } else {
            if node!.leftChild == nil {
                return node!.rightChild
            } else if node!.rightChild == nil {
                return node!.leftChild
            }

            node!.value = minValue(node: node!.rightChild)!

            node!.rightChild = deleteNode(node: node!.rightChild, value: node!.value)
        }

        return node
    }

    // Find the minimum value in a tree starting from a given node
    func minValue(node: Node?) -> Int? {
        var currentNode = node
        while currentNode?.leftChild != nil {
            currentNode = currentNode?.leftChild
        }
        return currentNode?.value
    }

    // Traverse the tree in pre-order starting from a given node
    func preOrderTraversal(node: Node?) {
        guard let node = node else {
