// Bubble Sort in Swift
// This program sorts an array of integers in ascending order using the bubble sort algorithm.

// Function to perform bubble sort on an array of integers
func bubbleSort(_ array: [Int]) -> [Int] {
    // Create a copy of the input array to avoid modifying the original
    var sortedArray = array

    // Outer loop: iterate through the array multiple times
    // The number of passes is equal to the length of the array minus 1
    for i in 0..<sortedArray.count {
        // Inner loop: compare adjacent elements and swap if they are in the wrong order
        // The inner loop runs from the start of the array to the end of the unsorted portion
